(()=>{"use strict";class t{constructor(){this.isTranslationActive=!1,this.initialize()}async initialize(){await this.loadCurrentState(),this.bindEventListeners(),await this.updateLearningStats(),await this.loadDictionarySettings()}bindEventListeners(){const t=document.getElementById("toggleTranslation");t?.addEventListener("click",()=>this.toggleTranslationMode());const e=document.getElementById("translateBtn");e?.addEventListener("click",()=>this.quickTranslate());const n=document.getElementById("vocabularyBtn");n?.addEventListener("click",()=>this.openVocabulary());const a=document.getElementById("reviewBtn");a?.addEventListener("click",()=>this.startReview());const s=document.getElementById("settingsBtn");s?.addEventListener("click",()=>this.openSettings());const i=document.getElementById("optionsBtn");i?.addEventListener("click",()=>this.openOptions()),document.querySelectorAll('.dictionary-item input[type="checkbox"]').forEach(t=>{t.addEventListener("change",()=>this.updateDictionarySettings())});const o=document.getElementById("inputText");o?.addEventListener("keydown",t=>{"Enter"!==t.key||t.shiftKey||(t.preventDefault(),this.quickTranslate())})}async loadCurrentState(){try{const[t]=await chrome.tabs.query({active:!0,currentWindow:!0});t?.id&&chrome.tabs.sendMessage(t.id,{action:"getTranslationStatus"},t=>{t&&t.isActive&&(this.isTranslationActive=!0,this.updateTranslationStatusUI())})}catch(t){console.error("加载当前状态失败:",t)}}async toggleTranslationMode(){try{const[t]=await chrome.tabs.query({active:!0,currentWindow:!0});t?.id&&chrome.tabs.sendMessage(t.id,{action:"toggleTranslation"},t=>{t&&t.success&&(this.isTranslationActive=t.isActive,this.updateTranslationStatusUI())})}catch(t){console.error("切换翻译模式失败:",t)}}updateTranslationStatusUI(){const t=document.getElementById("translationStatus"),e=document.getElementById("toggleTranslation");t&&e&&(this.isTranslationActive?(t.textContent="开启",e.textContent="关闭",e.classList.add("active")):(t.textContent="关闭",e.textContent="开启",e.classList.remove("active")))}async quickTranslate(){const t=document.getElementById("inputText"),e=document.getElementById("translateBtn"),n=document.getElementById("translateResult"),a=n.querySelector(".result-text");if(!(t&&e&&n&&a))return;const s=t.value.trim();if(s)try{e.disabled=!0,e.textContent="翻译中...";const t=await this.sendMessage({action:"translate",data:{text:s,targetLang:"zh-CN"}});if(!t.success)throw new Error(t.error);a.textContent=t.data.translatedText,n.style.display="block"}catch(t){console.error("快速翻译失败:",t),a.textContent="翻译失败，请稍后重试",n.style.display="block"}finally{e.disabled=!1,e.textContent="翻译"}}async updateLearningStats(){try{const t=await this.sendMessage({action:"getLearningStats"});if(t.success){const e=t.data,n=document.getElementById("totalWords"),a=document.getElementById("todayReviewed"),s=document.getElementById("reviewDue");n&&(n.textContent=e.totalWords||"0"),a&&(a.textContent=e.todayReviewed||"0"),s&&(s.textContent=e.reviewDue||"0")}}catch(t){console.error("更新学习统计失败:",t)}}async loadDictionarySettings(){try{const t=await this.sendMessage({action:"getSettings"});if(t.success){const e=t.data.activeDictionaries||[];document.querySelectorAll('.dictionary-item input[type="checkbox"]').forEach(t=>{t.checked=e.includes(t.value)})}}catch(t){console.error("加载词库设置失败:",t)}}async updateDictionarySettings(){try{const t=document.querySelectorAll('.dictionary-item input[type="checkbox"]:checked'),e=Array.from(t).map(t=>t.value);await this.sendMessage({action:"updateSettings",data:{activeDictionaries:e}})}catch(t){console.error("更新词库设置失败:",t)}}openVocabulary(){chrome.tabs.create({url:chrome.runtime.getURL("src/options/vocabulary.html")})}startReview(){chrome.tabs.create({url:chrome.runtime.getURL("src/options/review.html")})}openSettings(){chrome.runtime.openOptionsPage()}openOptions(){chrome.runtime.openOptionsPage()}sendMessage(t){return new Promise((e,n)=>{chrome.runtime.sendMessage(t,t=>{chrome.runtime.lastError?n(chrome.runtime.lastError):e(t)})})}}document.addEventListener("DOMContentLoaded",()=>{new t})})();